// Pull both ensures-foralls into the proof context with their natural triggers.
assert(forall|index: int| 0 <= index < N ==> #[trigger] post1_self_@[index] == 0);
assert(forall|index: int| 0 <= index < N ==> #[trigger] post2_self_@[index] == 0);

// `wf()` forces both views to have length `N`.
assert(post1_self_@.len() == N);
assert(post2_self_@.len() == N);

// Pointwise equality at every valid index: both sides are forced to be 0.
assert forall|i: int| 0 <= i < N implies post1_self_@[i] == post2_self_@[i] by {
    assert(post1_self_@[i] == 0);
    assert(post2_self_@[i] == 0);
}

// Sequence extensionality lifts pointwise equality to view equality.
assert(post1_self_@ =~= post2_self_@);
